/**
 * Standard v2 REST API response envelope.
 */
export type V2Response = {
    /**
     * Error details (present instead of result on failure).
     */
    error?: {
        /**
         * Machine-readable error code.
         */
        code?: string;
        /**
         * Human-readable error message.
         */
        message?: string;
    };
    /**
     * Pending notifications (combat, chat, trade, etc.) accumulated since last request.
     */
    notifications?: Array<{
        /**
         * Notification payload
         */
        data?: {
            [key: string]: unknown;
        };
        id?: string;
        timestamp?: string;
        /**
         * Notification category: system, combat, trade, chat, friend, tip
         */
        type?: string;
    }>;
    /**
     * Human-readable text summary when a renderer is available, otherwise the raw result data.
     */
    result?: unknown;
    /**
     * Current session info.
     */
    session?: {
        created_at?: string;
        expires_at?: string;
        id?: string;
        player_id?: string;
    };
    /**
     * Raw structured JSON data for programmatic access. Always present for successful game commands.
     */
    structuredContent?: {
        [key: string]: unknown;
    };
};

